    public List<ReceivableAdjustedEventResponse> getReceivableAdjustedEvents(
            TransactionReceipt transactionReceipt) {
        List<Contract.EventValuesWithLog> valueList = extractEventParametersWithLog(RECEIVABLEADJUSTED_EVENT, transactionReceipt);
        ArrayList<ReceivableAdjustedEventResponse> responses = new ArrayList<ReceivableAdjustedEventResponse>(valueList.size());
        for (Contract.EventValuesWithLog eventValues : valueList) {
            ReceivableAdjustedEventResponse typedResponse = new ReceivableAdjustedEventResponse();
            typedResponse.log = eventValues.getLog();
            typedResponse.receivableId = (byte[]) eventValues.getIndexedValues().get(0).getValue();
            typedResponse.adjuster = (String) eventValues.getIndexedValues().get(1).getValue();
            typedResponse.oldAmount = (BigInteger) eventValues.getNonIndexedValues().get(0).getValue();
            typedResponse.newAmount = (BigInteger) eventValues.getNonIndexedValues().get(1).getValue();
            typedResponse.reason = (String) eventValues.getNonIndexedValues().get(2).getValue();
            typedResponse.timestamp = (BigInteger) eventValues.getNonIndexedValues().get(3).getValue();
            responses.add(typedResponse);
        }
        return responses;
    }

